import { createSlice, CaseReducer, PayloadAction } from '@reduxjs/toolkit'

import { ShopItem } from '../../types'
export interface CartItem extends ShopItem {
  quantity: number
}

export type CartState = {
  visible: boolean
  items: CartItem[]
}

const toggleVisibility: CaseReducer<CartState> = (state) => {
  state.visible = !state.visible
}

const clearCart: CaseReducer<CartState> = (state) => {
  state.visible = false
  state.items = []
}

const clearItem: CaseReducer<CartState, PayloadAction<CartItem>> = (state, action) => {
  state.items = state.items.filter((item) => item.id !== action.payload.id)
}

const removeItem: CaseReducer<CartState, PayloadAction<CartItem>> = (state, action) => {
  const existingCartItem = state.items.find((item) => item.id === action.payload.id)

  if (!existingCartItem) return

  if (existingCartItem.quantity === 1) {
    state.items = state.items.filter((item) => item.id !== action.payload.id)
  } else {
    existingCartItem.quantity -= 1
  }
}

const saveItem: CaseReducer<CartState, PayloadAction<CartItem>> = (state, action) => {
  const existingCartItem = state.items.find((item) => item.id === action.payload.id) as CartItem

  if (existingCartItem) {
    existingCartItem.quantity = action.payload.quantity
  } else {
    state.items.push(action.payload)
  }
}

const initialState: CartState = {
  visible: false,
  items: [],
}

const cartSlice = createSlice({
  name: 'cart',
  initialState,
  reducers: {
    toggleVisibilityAction: toggleVisibility,
    saveItemAction: saveItem,
    clearItemAction: clearItem,
    removeItemAction: removeItem,
    clearCartAction: clearCart,
  },
})

// Extract the action creators object and the reducer
export const { actions, reducer } = cartSlice

// Extract and export each action creator by name
export const {
  toggleVisibilityAction,
  saveItemAction,
  clearItemAction,
  removeItemAction,
  clearCartAction,
} = actions

// Export the reducer, either as a default or named export
export default reducer

import { useMemo } from 'react'

import { ShoppingCartItem } from '../ShoppingCartItem/ShoppingCartItem'
import { CartItem } from '../../../app-state/cart'
import { Body } from '../../typography/Body'
import { toCurrency } from '../../../helpers'

import {
  OrderSummaryContainer,
  BottomContainer,
  CartItemsContainer,
  StyledHeading,
} from './OrderSummary.styles'

type OrderSummaryProps = {
  cartItems: CartItem[]
}

export const OrderSummary = ({ cartItems }: OrderSummaryProps) => {
  const totalPrice = useMemo(
    () => cartItems.map((item) => item.quantity * item.price).reduce((acc, next) => acc + next, 0),
    [cartItems]
  )
  return (
    <>
      <OrderSummaryContainer>
        <StyledHeading level={3} $withMargin>
          Your order
        </StyledHeading>
        <CartItemsContainer>
          {cartItems.length > 0 ? (
            cartItems.map((item) => <ShoppingCartItem key={item.id} item={item} />)
          ) : (
            <Body>Your cart is empty.</Body>
          )}
        </CartItemsContainer>
        <BottomContainer>
          <Body>Total</Body>
          <StyledHeading level={2}>{toCurrency(totalPrice)}</StyledHeading>
        </BottomContainer>
      </OrderSummaryContainer>
    </>
  )
}

import { useParams, useNavigate } from 'react-router-dom'
import styled from 'styled-components'

import { useFetchRestaurantsByCategory } from '../../api/hooks'
import { PageTemplate } from '../../templates/PageTemplate'
import { RestaurantCard, RestaurantCardSkeleton } from '../../components/RestaurantCard'
import { TopBanner } from '../../components/TopBanner'
import { categories } from '../../stub/categories'
import sushi from '../../assets/images/sushi.svg'
import { Restaurant } from '../../types'
import { ErrorBlock } from '../../components/ErrorBlock'
import { Breadcrumb } from '../../components/Breadcrumb'

const StyledContainer = styled.div`
  grid-template-columns: repeat(auto-fill, minmax(356px, 1fr));
  gap: 24px;
  display: grid;
  padding-bottom: 5rem;
`

export const CategoryDetailPage = () => {
  const { id } = useParams<'id'>()
  const navigate = useNavigate()

  const { restaurants, status } = useFetchRestaurantsByCategory(id)

  const category = categories.find((cat) => cat.id === id)

  return (
    <PageTemplate>
      <TopBanner
        title={category?.title || 'Oops!'}
        photoUrl={category?.photoUrl}
        onBackClick={() => navigate(-1)}
      />
      <div className="container">
        <Breadcrumb
          items={[
            { label: 'categories', path: '/categories' },
            { label: category?.title?.toLowerCase() || '' },
          ]}
        />
        {status === 'success' && restaurants.length <= 0 && (
          <ErrorBlock
            body="It seems that there are no restaurants in this category yet. Try to come back later?"
            title="This is not the food you're looking for."
            image={<img alt="no restaurants found" src={sushi} />}
            buttonText="See all restaurants"
            onButtonClick={() => {
              navigate('/categories')
            }}
          />
        )}
        <StyledContainer>
          {status === 'loading'
            ? Array.from({ length: 3 }).map((_, index) => <RestaurantCardSkeleton key={index} />)
            : restaurants.map((restaurant: Restaurant, index: number) => (
                <RestaurantCard
                  key={restaurant.name || index}
                  {...restaurant}
                  onClick={() => navigate(`/restaurants/${restaurant.id}`)}
                />
              ))}
        </StyledContainer>
      </div>
    </PageTemplate>
  )
}

import { createSlice, CaseReducer, PayloadAction } from '@reduxjs/toolkit'

import { CartItem } from '../cart'

export type OrderState = {
  items: CartItem[]
}

const saveOrder: CaseReducer<OrderState, PayloadAction<CartItem[]>> = (state, action) => {
  state.items = action.payload
}

const clearOrder: CaseReducer<OrderState> = (state) => {
  state.items = []
}

const initialState: OrderState = {
  items: [],
}

const orderSlice = createSlice({
  name: 'order',
  initialState,
  reducers: {
    saveOrderAction: saveOrder,
    clearOrderAction: clearOrder,
  },
})

// Extract the action creators object and the reducer
export const { actions, reducer } = orderSlice

// Extract and export each action creator by name
export const { saveOrderAction, clearOrderAction } = actions

// Export the reducer, either as a default or named export
export default reducer

