import type { Meta, StoryObj } from '@storybook/react-vite'
import { expect } from 'storybook/test'
import { Button } from './Button'

const meta = {
  component: Button,
  tags: ['ai-generated'],
} satisfies Meta<typeof Button>

export default meta
type Story = StoryObj<typeof meta>

export const Default: Story = {
  render: () => <Button>Order now</Button>,
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('button', { name: /order now/i })).toBeVisible()
  },
}

export const Large: Story = {
  render: () => <Button large>Continue to checkout</Button>,
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('button', { name: /continue to checkout/i })).toBeVisible()
  },
