import type { Meta, StoryObj } from '@storybook/react-vite'
import { expect } from 'storybook/test'
import { Button } from './Button'

const meta = {
  component: Button,
  tags: ['ai-generated'],
} satisfies Meta<typeof Button>

export default meta
type Story = StoryObj<typeof meta>

export const Default: Story = {
  render: () => <Button>Order now</Button>,
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('button', { name: /order now/i })).toBeVisible()
  },
}

export const Large: Story = {
  render: () => <Button large>Continue to checkout</Button>,
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('button', { name: /continue to checkout/i })).toBeVisible()
  },
}

export const Clear: Story = {
  render: () => <Button clear>Home</Button>,
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('button', { name: /home/i })).toBeVisible()
  },
}

export const WithIcon: Story = {
  render: () => <Button icon="cart">€12.50</Button>,
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('button', { name: /12\.50/i })).toBeVisible()
  },
}

export const Disabled: Story = {
  render: () => <Button disabled>Place order</Button>,
  play: async ({ canvas }) => {
    const btn = canvas.getByRole('button', { name: /place order/i })
    await expect(btn).toBeVisible()
    await expect(btn).toBeDisabled()
  },
}

